const needsHypermobility_S=(d)=>{
  const hm=String(Array.isArray(d.hm_screen)?d.hm_screen.join(", "):(d.hm_screen||"")).toLowerCase();
  return /multiple joint|beighton|loose.*since childhood|recurrent disloc/.test(hm);
};
