  // ── 3. Subscapularis tear — Magee; Netter's ──────────────────────────────
  const liftOffPos   = isBilPos("st_lift_off") && (has("st_lift_off_left","cannot")||has("st_lift_off_right","cannot")||has("st_lift_off","cannot"));
