  // ── 4. SLAP Lesion — O'Brien; Magee; Netter's ────────────────────────────
  const obrienSLAP = has("st_obrien_left","SLAP")||has("st_obrien_right","SLAP")||has("st_obrien","SLAP")||has("st_obrien_left","Both")||has("st_obrien_right","Both")||has("st_obrien","Both");
