  const sulcusGrade2 = has("st_sulcus_left","Grade 2")||has("st_sulcus_right","Grade 2")||has("st_sulcus_left","Grade 3")||has("st_sulcus_right","Grade 3")||has("st_sulcus","Grade 2")||has("st_sulcus","Grade 3");
